  let [see,setSee]=useState(false)
  return (
    <div>
      <div className='drop'>
        <div  onClick={()=>setSee(!see)} style={{cursor:'pointer'}} >clickkkk</div>
        <div className='ddd' ref={DDD} style={{ maxHeight: see? `${DDD.current.scrollHeight}px` : '0px',
        overflow:'hidden',transition:'all 0.34s ease-in'}}>

         <Seat_selection/>


        </div>
        {/* <div>
          <Seat_selection/>
        </div> */}

      </div>

      {/* <p>{DDD.current.clientHeight}</p> */}

    </div>
  )
}
